mapper.select:
SELECT sdd.sku_code,sdd.goods_name,sdd.sku_name,sdd.shop_id,IFNULL(reg.exchange_rate,1) AS exchange_rate,
       SUM(sdd.order_total) as order_total,SUM(sdd.order_amount) as order_amount,
       IFNULL(SUM(sdd.false_order_total),0) as false_order_total,IFNULL(SUM(sdd.false_order_amount),0) as false_order_amount,
       IFNULL(SUM(sdd.false_order_amount1),0) as false_order_amount1,
       IFNULL(SUM(sdd.true_order_total),0) as true_order_total,IFNULL(SUM(sdd.true_order_amount),0) as true_order_amount,
       IFNULL(SUM(sdd.ad_fee),0) AS ad_fee,IFNULL(SUM(sdd.ad_click),0) AS ad_click

FROM o_shop_daily_detail as sdd
left join o_shop as shop on shop.id = sdd.shop_id
left join o_shop_region as reg on reg.id = shop.region_id



     and sdd.date >= #{startDate}


     and sdd.date <= #{endDate}


        and sdd.region_id = #{regionId}


        and sdd.platform_id = #{platformId}


        and shop.manage_user_id = #{manageUserId}


        and shop.shop_group_id = #{shopGroupId}


        and sdd.shop_id = #{shopId}


        and sdd.sku_code = #{skuCode}



GROUP BY sdd.shop_id, sdd.sku_code,goods_name,sdd.sku_name
